	// Expected:
	// - Agent added 5 lines (base → shadow)
	// - User added 3 lines, removed 5 lines (shadow → head)
	// - humanModified = min(3, 5) = 3
	// - pureUserAdded = 3 - 3 = 0
	// - pureUserRemoved = 5 - 3 = 2
	// - agentLinesInCommit = 5 - 2 - 3 = 0
	// - Total = 5 + 0 - 2 = 3
